// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useMemo } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  windSpeedUnit: string; // Wind speed unit (km/h, mph, m/s, etc.)
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

function useComponent(props: Props) {
  const getWeatherEmoji = useCallback((condition: string): string => {
    const normalized = condition.toLowerCase().trim();
    if (normalized.includes('sunny') || normalized.includes('clear')) return '☀️';
    if (normalized.includes('cloudy') || normalized.includes('overcast')) return '☁️';
    if (normalized.includes('rainy') || normalized.includes('rain')) return '🌧️';
    if (normalized.includes('snow') || normalized.includes('snowy')) return '❄️';
    if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
    if (normalized.includes('wind')) return '💨';
    if (normalized.includes('fog') || normalized.includes('mist')) return '🌫️';
    if (normalized.includes('hot') || normalized.includes('heatwave')) return '🔥';
    return '🌤️';
  }, []);

  return {
    getWeatherEmoji,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth='sm' padding={24}>
      <Stack gap={24}>
        {/* Main Weather Card */}
        <Card shadow='md' padding={32} radius='lg'>
          <Stack gap={16} align='center'>
            {/* City Name */}
            <Heading level={2} color='var(--ggui-color-onSurface, #18181b)'>
              {props.city}
            </Heading>

            {/* Weather Icon and Condition */}
            <Stack gap={8} align='center'>
              <Text size='4xl' style={{ lineHeight: 1 }}>
                {state.getWeatherEmoji(props.condition)}
              </Text>
              <Text variant='body' color='var(--ggui-color-onSurfaceVariant, #52525b)'>
                {props.condition}
              </Text>
            </Stack>

            {/* Temperature (Large, Prominent) */}
            <Stack gap={2} align='center'>
              <Text
                size='4xl'
                weight='bold'
                color='var(--ggui-color-primary-600, #0284c7)'
              >
                {props.temperature}°{props.unit}
              </Text>
            </Stack>

            {/* Divider */}
            <Divider margin={8} />

            {/* Weather Details Grid (Humidity & Wind) */}
            <Stack direction='horizontal' gap={16} align='center' justify='around' style={{ width: '100%' }}>
              <Stack gap={4} align='center'>
                <Icon name='droplets' size={20} color='var(--ggui-color-primary-600, #0284c7)' />
                <Text variant='caption' color='var(--ggui-color-onSurfaceVariant, #52525b)'>
                  Humidity
                </Text>
                <Text variant='body' weight='semibold' color='var(--ggui-color-onSurface, #18181b)'>
                  {props.humidity}%
                </Text>
              </Stack>

              <Stack gap={4} align='center'>
                <Icon name='wind' size={20} color='var(--ggui-color-primary-600, #0284c7)' />
                <Text variant='caption' color='var(--ggui-color-onSurfaceVariant, #52525b)'>
                  Wind Speed
                </Text>
                <Text variant='body' weight='semibold' color='var(--ggui-color-onSurface, #18181b)'>
                  {props.windSpeed} {props.windSpeedUnit}
                </Text>
              </Stack>
            </Stack>
          </Stack>
        </Card>

        {/* 5-Day Forecast */}
        {props.forecast && props.forecast.length > 0 && (
          <Stack gap={12}>
            <Text variant='label' color='var(--ggui-color-onSurfaceVariant, #52525b)'>
              5-DAY FORECAST
            </Text>
            <Stack direction='horizontal' gap={8} wrap style={{ justifyContent: 'space-between' }}>
              {props.forecast.map((forecastDay, index) => (
                <Card
                  key={`forecast-${index}`}
                  shadow='sm'
                  padding={12}
                  radius='md'
                  style={{ flex: '1 1 calc(20% - 8px)', minWidth: '60px' }}
                >
                  <Stack gap={8} align='center'>
                    {/* Day Name */}
                    {forecastDay.day && (
                      <Text variant='caption' weight='semibold' color='var(--ggui-color-onSurface, #18181b)' align='center'>
                        {forecastDay.day}
                      </Text>
                    )}

                    {/* Icon/Emoji */}
                    {forecastDay.icon && (
                      <Text size='2xl' style={{ lineHeight: 1 }} align='center'>
                        {forecastDay.icon}
                      </Text>
                    )}

                    {/* High/Low Temps */}
                    <Stack gap={2} align='center'>
                      {forecastDay.high !== undefined && (
                        <Text variant='caption' weight='semibold' color='var(--ggui-color-primary-600, #0284c7)' align='center'>
                          {forecastDay.high}°
                        </Text>
                      )}
                      {forecastDay.low !== undefined && (
                        <Text variant='caption' color='var(--ggui-color-onSurfaceVariant, #52525b)' align='center'>
                          {forecastDay.low}°
                        </Text>
                      )}
                    </Stack>
                  </Stack>
                </Card>
              ))}
            </Stack>
          </Stack>
        )}
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { useAction } from '@ggui-ai/wire';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };

function useComponent(props: Props) {
  // Wire action hook
  const submit = useAction('submit');

  // State management
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState<number | null>(null);
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation
  const isValidEmail = (value: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
  const step1Valid = name.trim() !== '' && isValidEmail(email);
  const step2Valid = satisfaction !== null;
  const step3Valid = true; // Always valid, optional step
  const step4Valid = true; // Always valid, optional step

  const handleNext = () => {
    if (currentStep === 1 && !step1Valid) return;
    if (currentStep === 2 && !step2Valid) return;
    if (currentStep < 5) setCurrentStep(currentStep + 1);
  };

  const handleBack = () => {
    if (currentStep > 1) setCurrentStep(currentStep - 1);
  };

  const handleSubmit = () => {
    if (satisfaction !== null) {
      submit({ name, email, satisfaction, features, comments });
    }
  };

  return { currentStep, setCurrentStep, name, setName, email, setEmail, satisfaction, setSatisfaction, features, setFeatures, comments, setComments, step1Valid, step2Valid, handleNext, handleBack, handleSubmit, isValidEmail };
}
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const { currentStep, name, setName, email, setEmail, satisfaction, setSatisfaction, features, setFeatures, comments, setComments, step1Valid, handleNext, handleBack, handleSubmit, isValidEmail } = state;

  return (
    <Container maxWidth="md" padding={32}>
      <Stack gap={24}>
        {/* Progress indicator */}
        <div>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Step {currentStep} of 4</Text>
          <Progress value={currentStep} max={4} variant="default" size="md" showLabel={false} />
        </div>

        {/* Step 1: Name and Email */}
        {currentStep === 1 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>Personal Information</Heading>
              <Input
                label="Name"
                value={name}
                onChange={setName}
                placeholder="Enter your name"
                required
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={setEmail}
                placeholder="your@email.com"
                required
                error={email && !isValidEmail(email) ? 'Please enter a valid email' : ''}
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {currentStep === 2 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>How satisfied are you?</Heading>
              <RadioGroup
                label="Satisfaction"
                value={satisfaction !== null ? String(satisfaction) : ''}
                onChange={(val) => setSatisfaction(parseInt(val))}
                options={props.satisfactionLabels.map((label, idx) => ({ value: String(idx + 1), label }))}
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {currentStep === 3 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>Which features interest you?</Heading>
              <Stack gap={12}>
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={features.includes(feature)}
                    onChange={(checked) => {
                      if (checked) {
                        setFeatures([...features, feature]);
                      } else {
                        setFeatures(features.filter((f) => f !== feature));
                      }
                    }}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {currentStep === 4 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>Additional Comments</Heading>
              <TextArea
                label="Comments"
                value={comments}
                onChange={setComments}
                rows={6}
                maxLength={500}
                showCount
                placeholder="Share any additional feedback..."
              />
            </Stack>
          </Card>
        )}

        {/* Step 5: Review */}
        {currentStep === 5 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>Review Your Answers</Heading>
              <Stack gap={12}>
                <Box paddingY={8}>
                  <Text variant="label">Name</Text>
                  <Text variant="body">{name}</Text>
                </Box>
                <Divider />
                <Box paddingY={8}>
                  <Text variant="label">Email</Text>
                  <Text variant="body">{email}</Text>
                </Box>
                <Divider />
                <Box paddingY={8}>
                  <Text variant="label">Satisfaction</Text>
                  <Text variant="body">{satisfaction !== null ? props.satisfactionLabels[satisfaction - 1] : 'Not selected'}</Text>
                </Box>
                <Divider />
                <Box paddingY={8}>
                  <Text variant="label">Features of Interest</Text>
                  <Text variant="body">{features.length > 0 ? features.join(', ') : 'None selected'}</Text>
                </Box>
                <Divider />
                <Box paddingY={8}>
                  <Text variant="label">Comments</Text>
                  <Text variant="body">{comments || '(No comments)'}</Text>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation */}
        <Stack direction="horizontal" gap={12} justify="between">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          {currentStep < 5 ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={
                (currentStep === 1 && !step1Valid) ||
                (currentStep === 2 && satisfaction === null)
              }
            >
              Next
            </Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit}>
              Submit
            </Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useEffect } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const taskUpdate = (payload: ActionTaskUpdatePayload) => {
    window.dispatchEvent(new CustomEvent('ggui:action-taskUpdate', { detail: payload }));
  };

  // Streams — real-time from agent (.latest, .all)
  const [taskChangedData, setTaskChangedData] = useState<StreamTaskChanged | null>(null);
  const taskChanged = { latest: taskChangedData, all: [] as StreamTaskChanged[] };

  // State for tasks and UI
  const [localTasks, setLocalTasks] = useState(props.tasks || []);
  const [addingInColumn, setAddingInColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTaskColumn, setEditingTaskColumn] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');

  // Sync local tasks with props on mount/update
  React.useEffect(() => {
    setLocalTasks(props.tasks || []);
  }, [props.tasks]);

  // Listen for stream updates from agent
  useEffect(() => {
    const handleTaskChanged = (event: Event) => {
      const customEvent = event as CustomEvent<StreamTaskChanged>;
      setTaskChangedData(customEvent.detail);
    };
    window.addEventListener('ggui:agent-data', handleTaskChanged as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handleTaskChanged as EventListener);
  }, []);

  // Handle stream updates from other users
  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (action === 'create' && task) {
        setLocalTasks(prev => [...prev, task]);
      } else if (action === 'move' && task) {
        setLocalTasks(prev => prev.map(t => t.id === task.id ? { ...t, column: task.column } : t));
      } else if (action === 'edit' && task) {
        setLocalTasks(prev => prev.map(t => t.id === task.id ? { ...t, ...task } : t));
      } else if (action === 'delete' && task) {
        setLocalTasks(prev => prev.filter(t => t.id !== task.id));
      }
    }
  }, [taskChanged.latest]);

  const handleAddTask = useCallback((columnId: string) => {
    if (newTaskTitle.trim()) {
      const newTask = { id: Date.now().toString(), title: newTaskTitle, priority: newTaskPriority, column: columnId, assignee: '', dueDate: '' };
      setLocalTasks(prev => [...prev, newTask]);
      taskUpdate({ action: 'create', taskId: newTask.id, data: { column: columnId } });
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setAddingInColumn(null);
    }
  }, [newTaskTitle, newTaskPriority]);

  const handleMoveTask = useCallback((taskId: string, newColumn: string) => {
    setLocalTasks(prev => prev.map(t => t.id === taskId ? { ...t, column: newColumn } : t));
    taskUpdate({ action: 'move', taskId, data: { column: newColumn } });
  }, []);

  const handleEditTask = useCallback((taskId: string, newTitle: string) => {
    const currentColumn = editingTaskColumn || 'todo';
    setLocalTasks(prev => prev.map(t => t.id === taskId ? { ...t, title: newTitle } : t));
    taskUpdate({ action: 'edit', taskId, data: { column: currentColumn } });
    setEditingTaskId(null);
    setEditingTaskColumn(null);
  }, [editingTaskColumn]);

  const getPriorityColor = (priority?: string) => {
    switch (priority) {
      case 'high': return 'var(--ggui-color-error-500, #ef4444)';
      case 'medium': return 'var(--ggui-color-warning-500, #f59e0b)';
      case 'low': return 'var(--ggui-color-success-500, #22c55e)';
      default: return 'var(--ggui-color-outline, #d4d4d8)';
    }
  };

  const getTasksForColumn = (columnId: string) => localTasks.filter(t => t.column === columnId);
  const completedCount = getTasksForColumn('done').length;
  const totalCount = localTasks.length;

  return { taskUpdate, taskChanged, localTasks, setLocalTasks, addingInColumn, setAddingInColumn, newTaskTitle, setNewTaskTitle, newTaskPriority, setNewTaskPriority, editingTaskId, setEditingTaskId, editingTaskColumn, setEditingTaskColumn, editTitle, setEditTitle, handleAddTask, handleMoveTask, handleEditTask, getPriorityColor, getTasksForColumn, completedCount, totalCount };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="2xl" padding={24}>
      <Stack gap={24}>
        {/* Summary Bar */}
        <Box
          background="var(--ggui-color-primary-50, #f0f9ff)"
          padding={16}
          borderRadius={8}
        >
          <Stack direction="horizontal" justify="between" align="center">
            <Stack direction="horizontal" gap={32} align="center">
              <div>
                <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)">
                  Total Tasks
                </Text>
                <Heading level={3} color="var(--ggui-color-primary-900, #0c4a6e)">
                  {state.totalCount}
                </Heading>
              </div>
              <div>
                <Text variant="label" color="var(--ggui-color-success-600, #16a34a)">
                  Completed
                </Text>
                <Heading level={3} color="var(--ggui-color-success-900, #166534)">
                  {state.completedCount}
                </Heading>
              </div>
            </Stack>
            <Text variant="bodySmall" color="var(--ggui-color-primary-700, #0369a1)">
              {state.completedCount} of {state.totalCount} tasks completed
            </Text>
          </Stack>
        </Box>

        {/* Kanban Columns */}
        <Stack direction="horizontal" gap={20} align="start">
          {props.columns.map(column => {
            const columnTasks = state.getTasksForColumn(column.id || '');
            const isAdding = state.addingInColumn === column.id;

            return (
              <Box
                key={column.id}
                paddingX={0}
                paddingY={0}
                borderRadius={12}
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                style={{ flex: '1 1 300px', minHeight: '600px' }}
              >
                <Stack gap={12} align="stretch" style={{ height: '100%' }}>
                  {/* Column Header */}
                  <Box padding={16} borderRadius={0}>
                    <Stack direction="horizontal" justify="between" align="center">
                      <Stack direction="horizontal" gap={8} align="center">
                        <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
                          {column.name}
                        </Heading>
                        <Badge variant="secondary" size="sm">
                          {columnTasks.length}
                        </Badge>
                      </Stack>
                    </Stack>
                  </Box>

                  <Divider orientation="horizontal" margin={0} color="var(--ggui-color-outline, #d4d4d8)" />

                  {/* Task Cards Container */}
                  <Stack gap={12} align="stretch" style={{ flex: 1, overflow: 'auto', padding: '0 12px' }}>
                    {columnTasks.map(task => (
                      <Card
                        key={task.id}
                        padding={12}
                        shadow="sm"
                        radius="md"
                        as={Hoverable}
                        hoverStyle={{ boxShadow: 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))' }}
                      >
                        <Stack gap={8} align="stretch">
                          {/* Title Row */}
                          {state.editingTaskId === task.id ? (
                            <Stack direction="horizontal" gap={8} align="center">
                              <Input
                                value={state.editTitle}
                                onChange={state.setEditTitle}
                                placeholder="Task title"
                                size="sm"
                                style={{ flex: 1 }}
                              />
                              <Button
                                size="xs"
                                variant="primary"
                                onClick={() => state.handleEditTask(task.id || '', state.editTitle)}
                              >
                                Save
                              </Button>
                            </Stack>
                          ) : (
                            <Stack direction="horizontal" justify="between" align="start" gap={8}>
                              <Text
                                variant="body"
                                color="var(--ggui-color-onSurface, #18181b)"
                                as={Clickable}
                                onClick={() => {
                                  state.setEditingTaskId(task.id || null);
                                  state.setEditingTaskColumn(task.column || 'todo');
                                  state.setEditTitle(task.title || '');
                                }}
                                style={{ flex: 1, cursor: 'pointer' }}
                              >
                                {task.title}
                              </Text>
                              <Button
                                size="xs"
                                variant="ghost"
                                onClick={() => {
                                  state.setEditingTaskId(task.id || null);
                                  state.setEditingTaskColumn(task.column || 'todo');
                                  state.setEditTitle(task.title || '');
                                }}
                              >
                                <Icon name="edit" size={14} />
                              </Button>
                            </Stack>
                          )}

                          {/* Priority Badge */}
                          <Box>
                            <Badge
                              variant={
                                task.priority === 'high'
                                  ? 'error'
                                  : task.priority === 'medium'
                                    ? 'warning'
                                    : 'success'
                              }
                              size="sm"
                              pill
                            >
                              {task.priority || 'medium'}
                            </Badge>
                          </Box>

                          {/* Assignee & Due Date */}
                          <Stack direction="horizontal" justify="between" align="center" gap={8}>
                            {task.assignee ? (
                              <Avatar
                                name={task.assignee}
                                size="sm"
                                shape="circle"
                              />
                            ) : (
                              <Box style={{ width: '24px', height: '24px' }} />
                            )}
                            {task.dueDate && (
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                                {new Date(task.dueDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
