                                value: col.id || '',
                                label: col.name || 'Unknown',
                              }))}
                            value=""
                            onChange={(newColumnId) => state.handleMoveTask(task.id || '', newColumnId)}
                            placement="bottom-end"
                          />
                        </Stack>
                      </Card>
                    ))}
                  </Stack>

                  {/* Add Task Button / Form */}
                  <Box padding={12} style={{ marginTop: 'auto' }}>
                    {!isAdding ? (
                      <Button
                        fullWidth
                        variant="secondary"
                        onClick={() => state.setAddingInColumn(column.id || null)}
                      >
