                      </Button>
                    ) : (
                      <Stack gap={8} align="stretch">
                        <Input
                          value={state.newTaskTitle}
                          onChange={state.setNewTaskTitle}
                          placeholder="Task title"
                          size="sm"
                          autoFocus
                        />
                        <Select
                          value={state.newTaskPriority}
                          onChange={(val) => state.setNewTaskPriority(val as 'low' | 'medium' | 'high')}
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                          size="sm"
                        />
                        <Stack direction="horizontal" gap={8} align="center">
                          <Button
                            size="sm"
                            variant="primary"
                            onClick={() => state.handleAddTask(column.id || '')}
                            style={{ flex: 1 }}
                          >
                            Add
                          </Button>
                          <Button
                            size="sm"
                            variant="ghost"
                            onClick={() => {
                              state.setAddingInColumn(null);
                              state.setNewTaskTitle('');
                              state.setNewTaskPriority('medium');
                            }}
                            style={{ flex: 1 }}
                          >
                            Cancel
                          </Button>
                        </Stack>
                      </Stack>
                    )}
                  </Box>
                </Stack>
              </Box>
            );
          })}
        </Stack>
      </Stack>
    </Container>
  );
}

