// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}

function useComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  // Filter elements based on search query
  // Filter elements based on search query and valid row/col
  const filteredElements = useMemo(() => {
    const validElements = props.elements.filter((el) => el.row !== undefined && el.row !== null && el.col !== undefined && el.col !== null);
    if (!searchQuery.trim()) return validElements;
    const query = searchQuery.toLowerCase();
    return validElements.filter((el) => {
      const name = el.name?.toLowerCase() || '';
      const symbol = el.symbol?.toLowerCase() || '';
      return name.includes(query) || symbol.includes(query);
    });
  }, [searchQuery, props.elements]);

  // Get unique categories for legend
  const categories = useMemo(() => {
    const seen = new Set<string>();
    const result: Array<{ name: string; color: string }> = [];
    props.elements.forEach((el) => {
      if (el.category && !seen.has(el.category)) {
        seen.add(el.category);
        result.push({ name: el.category, color: getCategoryColor(el.category) });
      }
    });
    return result;
  }, [props.elements]);

  return {
    searchQuery,
    setSearchQuery,
    selectedElement,
    setSelectedElement,
    filteredElements,
    categories,
  };
}

// Helper function to map category to color token
function getCategoryColor(category: string): string {
  const categoryMap: Record<string, string> = {
    'Nonmetal': 'var(--ggui-color-success-500, #22c55e)',
    'Alkali Metal': 'var(--ggui-color-warning-500, #f59e0b)',
    'Alkaline Earth Metal': 'var(--ggui-color-warning-400, #fbbf24)',
    'Transition Metal': 'var(--ggui-color-primary-500, #0ea5e9)',
    'Lanthanide': 'var(--ggui-color-info-500, #06b6d4)',
    'Actinide': 'var(--ggui-color-info-400, #22d3ee)',
    'Halogen': 'var(--ggui-color-error-500, #ef4444)',
    'Noble Gas': 'var(--ggui-color-primary-600, #0284c7)',
    'Metalloid': 'var(--ggui-color-primary-400, #38bdf8)',
    'Post-transition Metal': 'var(--ggui-color-primary-300, #7dd3fc)',
    'Metal': 'var(--ggui-color-primary-200, #bae6fd)',
  };
  return categoryMap[category] || 'var(--ggui-color-outline, #d4d4d8)';
}

