}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };

function useComponent(props: Props) {
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const isOutOfStock = (props.product.stock ?? 0) === 0;
  const isLowStock = (props.product.stock ?? 0) > 0 && (props.product.stock ?? 0) <= 5;

  // Format price with currency
  const formattedPrice = props.product.currency && props.product.price !== undefined
    ? `${props.product.currency}${props.product.price.toFixed(2)}`
    : `$${(props.product.price ?? 0).toFixed(2)}`;

  const handleAddToCart = useCallback(() => {
    if (props.product.id) {
      const payload: ActionAddToCartPayload = { productId: props.product.id, quantity };
      // This would normally dispatch to an agent action, but for now we log
      console.log('Add to Cart:', payload);
    }
  }, [props.product.id, quantity]);

  const handleQuantityChange = useCallback((value: number) => {
    const max = props.product.stock ?? 1;
    const newValue = Math.max(1, Math.min(value, max));
    setQuantity(newValue);
  }, [props.product.stock]);

  return { quantity, setQuantity, activeTab, setActiveTab, isOutOfStock, isLowStock, formattedPrice, handleAddToCart, handleQuantityChange };
}

export default function Component(props: Props) {
