import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };

function useComponent(props: Props) {
  // State
  const [messages, setMessages] = useState(props.messages);
  const [inputValue, setInputValue] = useState('');
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const messagesEndRef = useRef<HTMLDivElement>(null);



  // Auto-scroll to bottom on new messages
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  // Handle new messages from stream via ggui:agent-data event
  useEffect(() => {
    const handleAgentData = (event: any) => {
      const { type, payload } = event.detail || {};
      if (type === 'message' && payload) {
        setMessages(prev => [...prev, payload]);
        setTimeout(() => scrollToBottom(), 0);
      }
    };

    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, [scrollToBottom]);

  // Handle typing indicator from stream via ggui:agent-data event
  useEffect(() => {
    const handleAgentData = (event: any) => {
      const { type, payload } = event.detail || {};
      if (type === 'typing' && payload) {
        const { sender, active } = payload;
        if (sender && sender !== props.currentUser) {
          setTypingUsers(prev => {
            const next = new Set(prev);
            if (active) {
              next.add(sender);
            } else {
              next.delete(sender);
            }
            return next;
          });
        }
      }
    };

    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, [props.currentUser]);

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      const payload: ActionSendMessagePayload = { text: inputValue, timestamp: new Date().toISOString() };
      window.dispatchEvent(new CustomEvent('ggui:client-action', { detail: { action: 'sendMessage', payload } }));
      setInputValue('');
      scrollToBottom();
    }
  }, [inputValue, scrollToBottom]);

  // Handle Enter key in input
  const handleKeyPress = useCallback((e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  }, [handleSendMessage]);

  return { messages, inputValue, setInputValue, handleSendMessage, handleKeyPress, typingUsers, scrollToBottom, messagesEndRef };
}

