// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };

function useComponent(props: Props) {
  // State for merged stocks and live updates
  const [stocks, setStocks] = useState(props.stocks);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [highlightedSymbols, setHighlightedSymbols] = useState<Set<string>>(new Set());
  const [marketStatus, setMarketStatus] = useState<StreamMarketStatus | null>(null);

  // Listen for real-time price updates via ggui:agent-data events
  useEffect(() => {
    const handleAgentData = (event: CustomEvent) => {
      const data = event.detail;
      if (data.type === 'priceUpdate') {
        const update = data.data as StreamPriceUpdate;
        setStocks((prev) =>
          prev.map((stock) =>
            stock.symbol === update.symbol
              ? { ...stock, price: update.price ?? stock.price, change: update.change ?? stock.change, changePercent: update.changePercent ?? stock.changePercent }
              : stock
          )
        );
        setLastUpdated(new Date());
        // Highlight the updated stock briefly
        if (update.symbol) {
          setHighlightedSymbols((prev) => new Set(prev).add(update.symbol));
          setTimeout(() => {
            setHighlightedSymbols((prev) => {
              const next = new Set(prev);
              next.delete(update.symbol!);
              return next;
            });
          }, 800);
        }
      } else if (data.type === 'marketStatus') {
        setMarketStatus(data.data as StreamMarketStatus);
      }
    };

    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
  }, []);

  return { stocks, lastUpdated, marketStatus, highlightedSymbols };
}

