  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };

function useComponent(props: Props) {
  // Action callback — will be called by component
  const handleComplete = useCallback((data: ActionCompletePayload) => {
    // This will be invoked when user completes onboarding
    console.log('Onboarding completed:', data);
  }, []);
  // State management
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || (props.avatarOptions[0] || '👤'),
    role: props.initialProfile.role || (props.roleOptions[0] || ''),
    emailNotifications: props.initialProfile.emailNotifications !== undefined ? props.initialProfile.emailNotifications : true,
    theme: props.initialProfile.theme || 'light',
  });

  // Validation
  const isValidEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isStep1Valid = formData.name.trim() !== '' && isValidEmail(formData.email);
  const isStep2Valid = formData.role !== '';

  // Navigation handlers
  const handleNext = useCallback(() => {
    if (currentStep < 3) {
      setCurrentStep(currentStep + 1);
    }
  }, [currentStep]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  const handleCompleteSetup = useCallback(() => {
    if (isStep1Valid && isStep2Valid) {
      handleComplete(formData);
    }
  }, [formData, isStep1Valid, isStep2Valid, handleComplete]);

  // Form handlers
  const handleInputChange = useCallback((field: string, value: string | boolean) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  }, []);

  const handleAvatarSelect = useCallback((avatar: string) => {
    setFormData(prev => ({ ...prev, avatar }));
  }, []);

  return {
    currentStep,
    setCurrentStep,
    formData,
    handleNext,
    handleBack,
    handleCompleteSetup,
    handleInputChange,
    handleAvatarSelect,
    isStep1Valid,
    isStep2Valid,
    isValidEmail,
  };
}

