            {[1, 2, 3].map((step) => (
              <Box key={step} style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-2, 8px)' }}>
                <Box
                  padding={8}
                  borderRadius="var(--ggui-shape-radius-full, 9999px)"
                  background={step <= state.currentStep ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outlineVariant, #e4e4e7)'}
                  style={{
                    width: '40px',
                    height: '40px',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    transition: 'all 200ms ease-in-out',
                  }}
                >
                  <Text
                    variant="label"
                    color={step <= state.currentStep ? '#ffffff' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                    align="center"
                  >
                    {step}
                  </Text>
                </Box>
                {step < 3 && (
                  <Box
                    style={{
                      height: '2px',
                      width: '40px',
                      background: step < state.currentStep ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outlineVariant, #e4e4e7)',
                      transition: 'all 200ms ease-in-out',
                    }}
                  />
                )}
              </Box>
            ))}
          </Row>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Step {state.currentStep} of 3</Text>
        </Stack>

        {/* Content Card */}
        <Card shadow="md" padding={32} radius="lg">
          {state.currentStep === 1 && renderStep1()}
          {state.currentStep === 2 && renderStep2()}
          {state.currentStep === 3 && renderStep3()}
        </Card>

        {/* Navigation Buttons */}
        <Row gap={12} justify="between" align="center">
          <Button
            variant="outline"
            onClick={state.handleBack}
            disabled={state.currentStep === 1}
          >
            Back
          </Button>
          <Spacer size="flex" />
          {state.currentStep < 3 && (
            <Button
              variant="primary"
              onClick={state.handleNext}
              disabled={state.currentStep === 1 ? !state.isStep1Valid : !state.isStep2Valid}
            >
              Next
            </Button>
          )}
           {state.currentStep === 3 && (
             <Button
               variant="primary"
               onClick={state.handleCompleteSetup}
               disabled={!state.isStep1Valid || !state.isStep2Valid}
             >
               Complete Setup
             </Button>
           )}
          )}
        </Row>
      </Stack>
    </Container>
  );
}
